import React, { useState, useEffect } from 'react';

interface NavbarProps {
  currentPage: string;
  onNavigate: (page: string) => void;
}

export const Navbar: React.FC<NavbarProps> = ({ currentPage, onNavigate }) => {
  const [expanded, setExpanded] = useState(false);
  const [scrolled, setScrolled] = useState(false);

  useEffect(() => {
    const handleScroll = () => setScrolled(window.scrollY > 50);
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  const navLinks = [
    { id: 'home', label: 'Ekhaya', icon: 'fa-house' },
    { id: 'about', label: 'Legacy', icon: 'fa-landmark' },
    { id: 'programs', label: 'Action', icon: 'fa-hand-fist' },
    { id: 'knowledge', label: 'Wisdom', icon: 'fa-book-open' },
    { id: 'events', label: 'Events', icon: 'fa-calendar-days' },
  ];

  const handleNav = (id: string) => {
    onNavigate(id);
    setExpanded(false);
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  return (
    <>
      {/* Floating Dock Navigation */}
      <nav 
        className={`fixed left-1/2 -translate-x-1/2 z-50 transition-all duration-500 ease-out ${
          scrolled || expanded ? 'top-6' : 'top-8 md:top-10'
        }`}
      >
        <div 
          className={`relative bg-[#1A0F0E]/90 backdrop-blur-xl border border-[#D4AF37]/20 shadow-2xl transition-all duration-500 overflow-hidden ${
            expanded 
              ? 'w-[90vw] md:w-[600px] rounded-[2rem] p-2' 
              : 'w-auto rounded-full p-2 pl-4 pr-2'
          }`}
        >
          {/* Collapsed State Header */}
          <div className="flex items-center justify-between">
            <button 
              onClick={() => handleNav('home')}
              className={`flex items-center gap-3 group ${expanded ? 'ml-4 mt-2 mb-4' : ''}`}
            >
              <div className="relative w-10 h-10 flex items-center justify-center bg-[#D4AF37] rounded-full text-[#1A0F0E] font-black border-2 border-white/10 group-hover:rotate-180 transition-transform duration-700">
                IN
              </div>
              <span className={`text-white font-bold tracking-widest uppercase text-xs transition-opacity duration-300 ${
                expanded ? 'opacity-100' : 'opacity-0 w-0 overflow-hidden group-hover:w-auto group-hover:opacity-100 md:opacity-100 md:w-auto'
              }`}>
                Insizwa<span className="text-[#D4AF37]">.</span>
              </span>
            </button>

            {/* Trigger Button */}
            <button 
              onClick={() => setExpanded(!expanded)}
              className={`w-10 h-10 rounded-full flex items-center justify-center transition-all duration-300 ${
                expanded 
                  ? 'bg-white/10 text-white rotate-90 absolute top-4 right-4' 
                  : 'bg-[#D4AF37]/10 text-[#D4AF37] hover:bg-[#D4AF37] hover:text-[#1A0F0E] ml-4'
              }`}
            >
              <i className={`fa-solid ${expanded ? 'fa-xmark' : 'fa-bars-staggered'}`}></i>
            </button>
          </div>

          {/* Expanded Menu Grid */}
          <div className={`transition-all duration-500 ease-out ${
            expanded ? 'max-h-[500px] opacity-100 mt-4' : 'max-h-0 opacity-0'
          }`}>
            <div className="grid grid-cols-2 md:grid-cols-3 gap-2 pb-2">
              {navLinks.map((link) => (
                <button
                  key={link.id}
                  onClick={() => handleNav(link.id)}
                  className={`flex flex-col items-center justify-center p-6 rounded-2xl transition-all duration-300 group ${
                    currentPage === link.id 
                      ? 'bg-[#D4AF37] text-[#1A0F0E]' 
                      : 'bg-white/5 text-white/60 hover:bg-white/10 hover:text-white'
                  }`}
                >
                  <i className={`fa-solid ${link.icon} text-xl mb-2 group-hover:scale-110 transition-transform`}></i>
                  <span className="text-[10px] font-black uppercase tracking-widest">{link.label}</span>
